Add state and validation logic:

const [validationState, setValidationState] = useState<'idle' | 'loading' | 'valid' | 'invalid'>('idle');
const [error, setError] = useState<string | null>(null);

// Debounced validation
const debouncedValue = useDebounce(value, 500);

useEffect(() => {
  if (!debouncedValue) {
    setValidationState('idle');
    return;
  }

  setValidationState('loading');

  fetch('/api/settings/validate-api-key', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ provider, api_key: debouncedValue }),
  })
    .then(res => res.json())
    .then(data => {
      if (data.valid) {
        setValidationState('valid');
        setError(null);
        onValidationChange?.(true);
      } else {
        setValidationState('invalid');
        setError(data.error || 'Invalid API key');
        onValidationChange?.(false);
      }
    })
    .catch(() => {
      setValidationState('invalid');
      setError('Validation failed');
    });
}, [debouncedValue, provider]);

